import React, { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import api from '../axios';

export default function Login() {
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState('');
  const navigate = useNavigate();

  async function handleSubmit(e) {
    e.preventDefault();
    try {
      const { data } = await api.post('/auth/login', { email, password });
      localStorage.setItem('token', data.token);
      navigate('/');
    } catch (err) {
      setError('Invalid credentials');
    }
  }

  return (
    <div className="max-w-sm mx-auto bg-white p-4 rounded border">
      <h1 className="text-xl font-semibold mb-3">Login</h1>
      {error && <div className="text-sm text-red-600 mb-2">{error}</div>}
      <form onSubmit={handleSubmit} className="grid gap-3">
        <div>
          <label className="block text-sm font-medium">Email</label>
          <input type="email" className="mt-1 w-full border rounded px-3 py-2" value={email} onChange={(e) => setEmail(e.target.value)} required />
        </div>
        <div>
          <label className="block text-sm font-medium">Password</label>
          <input type="password" className="mt-1 w-full border rounded px-3 py-2" value={password} onChange={(e) => setPassword(e.target.value)} required />
        </div>
        <button className="px-4 py-2 bg-blue-600 text-white rounded">Login</button>
      </form>
      <div className="text-sm mt-3">No account? <Link to="/register" className="text-blue-600">Register</Link></div>
    </div>
  );
}
